BEGIN;
INSERT INTO "Tour" (id, slug, title, description, "pricePerPerson", currency, "priceNote", "groupSize", type, destination, image, gallery, "specialOffer", dates, duration, "startDate", "endDate", highlights, included, "notIncluded", itinerary, faq, featured, active, "order", "createdAt", "updatedAt") VALUES (gen_random_uuid()::text, 'dubai-turu', $q$Dubai & Abu Dabi Turu$q$, $q$Burj Khalifa, çöl safarisi, Abu Dabi Şeyh Zayed Camii ve Marina tekne turuyla 5 günlük butik Dubai & Abu Dabi deneyimi. Namaz vakitlerine uygun, vize dahil.$q$, 1200, 'EUR', $q$Çocuk (2-6 yaş): 800 EUR · Bebek (0-2 yaş): 300 EUR · 200 EUR kapora ile rezervasyon · Yeşil pasaport sahiplerine 75 EUR indirim (vizesiz giriş) · Vize hizmeti ve ücreti fiyata dahildir.$q$, $q$Maksimum 15 kişi (butik)$q$, 'international', $q$Dubai & Abu Dabi, BAE$q$, $q$/images/tours/dubai.jpg$q$, ARRAY[]::text[], false, $q$25 - 30 Mart 2026$q$, $q$5 gün / 4 gece$q$, '2026-03-25', '2026-03-30', ARRAY[$q$5 yıldızlı Elite Byblos'ta 4 gece kahvaltı dahil konaklama$q$,$q$Burj Khalifa 123. kat (giriş dahil) ve Dubai Mall su & ışık gösterisi$q$,$q$4x4 çöl safarisi ve akşam yemekli bedevi kampı$q$,$q$Marina'da akşam yemekli tekne turu$q$,$q$Abu Dabi şehir turu & Şeyh Zayed Camii$q$,$q$Global Village ve Miracle Garden (girişler dahil)$q$,$q$Air Arabia ile gidiş-dönüş uçak bileti (+20 kg bagaj)$q$,$q$Vize hizmeti ve ücreti dahil · Namaz vakitlerine uygun program$q$]::text[], ARRAY[$q$Sabiha Gökçen - Sharjah gidiş-dönüş Air Arabia uçak bileti (+20 kg bagaj)$q$,$q$5 yıldızlı Elite Byblos otelde 4 gece konaklama (kahvaltı dahil)$q$,$q$Şehir içi ve şehirlerarası tüm transferler$q$,$q$4 kahvaltı ve 2 akşam yemeği$q$,$q$Tüm müze ve ören yeri giriş ücretleri$q$,$q$4x4 araçlarla çöl safarisi ve akşam yemekli otantik bedevi kampı$q$,$q$Marina'da akşam yemekli tekne turu$q$,$q$Burj Khalifa 123. kat giriş bileti$q$,$q$Miracle Garden ve Global Village giriş biletleri$q$,$q$Abu Dabi ve Dubai şehir turları$q$,$q$Seyahat sigortası$q$,$q$Vize hizmeti ve ücreti$q$]::text[], ARRAY[$q$Yurt dışı çıkış harcı (havalimanında 1250 TL)$q$,$q$1 kahvaltı, öğle yemekleri ve 3 akşam yemeği$q$,$q$Tüm şahsi harcamalar$q$,$q$Yerel bahşişler (ortalama 10 dolar)$q$]::text[], $itin$[{"day":"1. Gün","date":"25 Mart - Dubai İkonları & Global Village","title":"İstanbul - Dubai · Burj Al Arab & Global Village","activities":["Sabiha Gökçen buluşma (24 Mart 21:00)","Sharjah'a varış (05:45)","Burj Al Arab fotoğraf molası","Bluewaters Island & Ain Dubai","Gelecek Müzesi","Global Village (serbest zaman)"],"description":"24 Mart akşamı 21:00'de Sabiha Gökçen'de buluşuyoruz; uçağımız 25 Mart 00:35'te kalkıyor, 05:45'te Sharjah'a varıyoruz ve Dubai'ye geçiyoruz. Dubai'nin simgesi Burj Al Arab önünde fotoğraf molası, ardından Bluewaters Island ve Ain Dubai. Gelecek Müzesi'nin ilk katını gezip otele yerleşiyoruz. Akşam 18:00 gibi dünya kültürlerini bir araya getiren Global Village'a geçiyor, serbest zamanda dünya mutfaklarını tadıp alışveriş yapıyoruz. Gece otele dönüş."},{"day":"2. Gün","date":"26 Mart - Safari & Bedevi Gecesi","title":"Çöl Safarisi ve Bedevi Kampı","activities":["Otel kahvaltısı","Emirates Mall (serbest)","4x4 çöl safarisi & kum sörfü","Gün batımı fotoğraf molası","Bedevi kampında açık büfe akşam yemeği","Şov ve dans gösterileri"],"description":"Kahvaltının ardından serbest zaman (yürüme mesafesindeki Emirates Mall). Öğleden sonra altın çöllerde 4x4 araçlarla safari, kum sörfü ve gün batımında fotoğraflar. Akşam çölde kurulan bedevi kampında açık büfe yemek, ardından şov ve dans gösterileri. Otele dönüş."},{"day":"3. Gün","date":"27 Mart - Abu Dabi & Burj Khalifa","title":"Abu Dabi Şehir Turu · Burj Khalifa 123. Kat","activities":["Şeyh Zayed Camii","Emirates Palace","Abu Dabi Corniche","Dubai Mall","Burj Khalifa 123. kat (giriş dahil)","Su & ışık gösterisi"],"description":"Kahvaltı sonrası özel aracımızla Abu Dabi'ye; İslam dünyasının en zarif yapılarından Şeyh Zayed Camii, Emirates Palace ve Corniche. Dubai'ye dönüşte Dubai Mall ve dünyanın en yüksek binası Burj Khalifa'nın 123. katından şehir manzarası (giriş dahil). Akşam su & ışık gösterisi ve serbest zaman."},{"day":"4. Gün","date":"28 Mart - Eski Dubai & Marina Tekne Turu","title":"Dubai Şehir Turu · Marina Akşam Yemekli Tekne Turu","activities":["Al Seef & abra turu","Palm Adası & Atlantis","Souk Madinat Jumeirah","Marina'da akşam yemekli tekne turu"],"description":"Kahvaltı sonrası Eski Dubai çarşıları ve Al Seef'te gezinti (abra turu, alışveriş). Palm Adası ve Atlantis Oteli'ni turlayıp Souk Madinat Jumeirah'ın mimarisinin keyfini çıkarıyoruz. Akşam Marina'da açık büfe akşam yemekli tekne turuyla Dubai'nin ışıltısını izliyoruz."},{"day":"5. Gün","date":"29 Mart - Miracle Garden & Dönüş","title":"Miracle Garden · Dubai Outlet Mall · Dönüş","activities":["Otel çıkışı","Miracle Garden","Dubai Outlet Mall (serbest)","Dönüş uçuşu (20:50)"],"description":"Kahvaltı ve check-out sonrası dünyanın en büyük çiçek bahçesi Miracle Garden ve son alışveriş için Dubai Outlet Mall. 18:00'de Sharjah Havalimanı'nda oluyor, 20:50 uçağımızla dönüyoruz; 30 Mart 00:20'de İstanbul."}]$itin$::jsonb, $faq$[{"question":"İptal ve iade koşulları nelerdir?","answer":"Tur tarihine 30 günden daha uzun süre varken yapılan iptallerde ödemenizin tamamı iade edilir. Tura 21-30 gün kala yapılan iptallerde tutarın %50'si tahsil edilir. 21 günden az süre kala yapılan iptallerde ücretin tamamı tahsil edilir."},{"question":"Rezervasyon ve ödeme nasıl yapılır?","answer":"200 EUR kapora ile kesin kayıt oluşur; kalan tutar 10 Mart'a kadar taksitlendirilebilir (1 Mart itibarıyla yarısı ödenmiş olmalıdır). Çocuk (2-6 yaş) 800 EUR, bebek (0-2 yaş) 300 EUR."},{"question":"Vize gerekiyor mu?","answer":"Vize hizmeti ve ücreti fiyata dahildir. Yeşil pasaport sahipleri BAE'ye vizesiz girebilir ve 75 EUR indirim hakkına sahiptir."},{"question":"Uçuş bilgileri nelerdir?","answer":"Gidiş: 25 Mart 00:35 Sabiha Gökçen → Sharjah (Air Arabia G9284). Dönüş: 29 Mart 20:50 Sharjah → Sabiha Gökçen, 30 Mart 00:20 varış (G9285). 20 kg bagaj dahil."},{"question":"Konaklama nerede?","answer":"5 yıldızlı Elite Byblos otelde 4 gece, kahvaltı dahil."},{"question":"Kimler katılabilir?","answer":"Turlarımız aile ve hanımların katılımına uygundur; grubun uyumu ve misafirlerimizin konforu için bireysel erkek misafir kabul edemiyor, beylerin anlayışına sığınıyoruz. Erkek misafirlerimiz aile veya grup katılımıyla aramıza katılabilir. Maksimum 15 kişilik butik gruplar."},{"question":"Pasaport için bir şart var mı?","answer":"Pasaportunuzun, gezi bitiş tarihi itibarıyla en az 6 ay geçerli olması gerekmektedir."}]$faq$::jsonb, false, true, 22, now(), now())
ON CONFLICT (slug) DO UPDATE SET title=EXCLUDED.title, description=EXCLUDED.description, "pricePerPerson"=EXCLUDED."pricePerPerson", currency=EXCLUDED.currency, "priceNote"=EXCLUDED."priceNote", "groupSize"=EXCLUDED."groupSize", type=EXCLUDED.type, destination=EXCLUDED.destination, image=EXCLUDED.image, dates=EXCLUDED.dates, duration=EXCLUDED.duration, "startDate"=EXCLUDED."startDate", "endDate"=EXCLUDED."endDate", highlights=EXCLUDED.highlights, included=EXCLUDED.included, "notIncluded"=EXCLUDED."notIncluded", itinerary=EXCLUDED.itinerary, faq=EXCLUDED.faq, featured=EXCLUDED.featured, "order"=EXCLUDED."order", "updatedAt"=now();
INSERT INTO "Tour" (id, slug, title, description, "pricePerPerson", currency, "priceNote", "groupSize", type, destination, image, gallery, "specialOffer", dates, duration, "startDate", "endDate", highlights, included, "notIncluded", itinerary, faq, featured, active, "order", "createdAt", "updatedAt") VALUES (gen_random_uuid()::text, 'fas-turu', $q$Binbir Gece Masalları & Baştan Başa Fas Turu$q$, $q$Kazablanka, Marakeş, Essaouira, Rabat, Tanca, Şefşaven ve Fes; Hasan II Camii'nden UNESCO medinalara 7 günlük her şey dahil Fas turu. Namaz vakitlerine uygun.$q$, 1475, 'EUR', $q$Çocuk (2-6 yaş): 1.050 EUR · Bebek (0-2 yaş): 400 EUR · 375 EUR kapora ile rezervasyon.$q$, $q$Maksimum 15 kişi (butik)$q$, 'international', $q$Fas (Kazablanka · Marakeş · Tanca · Fes)$q$, $q$/images/tours/fas.jpg$q$, ARRAY[]::text[], false, $q$4 - 10 Temmuz 2026$q$, $q$7 gün / 6 gece$q$, '2026-07-04', '2026-07-10', ARRAY[$q$Marakeş, Kazablanka, Tanca ve Fes; 7 şehir tek turda$q$,$q$Hasan II Camii (İslam dünyasının en büyük camilerinden)$q$,$q$UNESCO Fes el-Bali Medinası & Karaouiyine Üniversitesi$q$,$q$Mavi şehir Şefşaven ve Atlantik kıyısı Essaouira$q$,$q$Bahia Sarayı, Koutoubia Camii, Jemaa el-Fna$q$,$q$6 gece 3-4 yıldızlı otel, kahvaltı ve akşam yemekleri dahil$q$,$q$Air Arabia ile gidiş-dönüş uçak bileti (+20 kg bagaj, ikram dahil)$q$,$q$Namaz vakitlerine uygun program · Her şey dahil$q$]::text[], ARRAY[$q$Sabiha Gökçen - Kazablanka gidiş-dönüş Air Arabia uçak bileti (+20 kg bagaj, ikram dahil)$q$,$q$6 gece 3-4 yıldızlı otellerde konaklama (kahvaltı dahil)$q$,$q$Şehir içi ve şehirlerarası tüm transferler$q$,$q$Tüm kahvaltı ve akşam yemekleri$q$,$q$Tüm müze ve ören yeri giriş ücretleri$q$,$q$Seyahat sigortası$q$]::text[], ARRAY[$q$Yurt dışı çıkış harcı (havalimanında 1250 TL)$q$,$q$Tüm şahsi harcamalar$q$,$q$Yerel bahşişler (ortalama 10 EUR)$q$]::text[], $itin$[{"day":"1. Gün","date":"4 Temmuz - Kazablanka & Marakeş","title":"İstanbul - Kazablanka - Marakeş (Şehir Turu 1)","activities":["Sabiha Gökçen buluşma (3 Temmuz 22:30)","Kazablanka'ya varış (04:35)","Marakeş'e transfer","Bahia Sarayı","Ben Youssef Medresesi","Koutoubia Camii","Jemaa el-Fna Meydanı & Medina"],"description":"3 Temmuz 22:30'da Sabiha Gökçen'de buluşuyoruz; 01:30 uçağımızla Kazablanka'ya hareket edip 04:35'te varıyoruz. Yaklaşık 2 saat 45 dakikalık transferle Marakeş'e geçip kahvaltının ardından şehir turuna başlıyoruz: Bahia Sarayı, Ben Youssef Medresesi, Koutoubia Camii ve Jemaa el-Fna Meydanı ile çevresindeki Medina. Otele dönüş, akşam yemeği ve serbest zaman. Konaklama Marakeş'te."},{"day":"2. Gün","date":"5 Temmuz - Essaouira","title":"Marakeş - Essaouira - Marakeş","activities":["Essaouira'ya transfer (~3 saat)","UNESCO Essaouira Medinası","Skala de la Kasbah","Balıkçı limanı","Marakeş'e dönüş"],"description":"Kahvaltı sonrası Atlantik kıyısındaki Essaouira'ya (~3 saat) gidiyoruz. Mavi-beyaz mimarisi, surlarla çevrili UNESCO Dünya Mirası Medinası, dar sokakları, sanat atölyeleri ve geleneksel pazarları; Skala de la Kasbah ve balıkçı limanı. Serbest zamanın ardından akşam Marakeş'e dönüş. Konaklama Marakeş'te."},{"day":"3. Gün","date":"6 Temmuz - Marakeş & Kazablanka","title":"Marakeş Şehir Turu 2 - Kazablanka","activities":["Majorelle Bahçesi","Kazablanka'ya transfer (~3,5 saat)","Hasan II Camii","Corniche","BM Meydanı"],"description":"Kahvaltı sonrası Marakeş'in sanat ve botanik kimliğini yansıtan Majorelle Bahçesi'ni gezip ~3,5 saatlik yolculukla Kazablanka'ya geçiyoruz. İslam dünyasının en büyük camilerinden Hasan II Camii, Corniche sahil yolu ve Birleşmiş Milletler Meydanı. Medina'da son alışveriş. Konaklama Kazablanka'da."},{"day":"4. Gün","date":"7 Temmuz - Rabat & Tanca","title":"Kazablanka - Rabat - Tanca Şehir Turu","activities":["Hassan Kulesi & V. Muhammed Türbesi","Oudaya Kasbah","Tanca'ya transfer (~2,5 saat)","Kasbah & Medina","Cap Spartel","Grand & Petit Socco"],"description":"Kahvaltı sonrası ~1 saatte başkent Rabat'a; Hassan Kulesi ve V. Muhammed Türbesi, Atlantik kıyısındaki Oudaya Kasbah ve Kraliyet Sarayı çevresi. Ardından ~2,5 saatte Atlantik ile Akdeniz'in buluştuğu Tanca'ya; Kasbah ve Medina, Atlantik-Akdeniz buluşmasının panoramik noktası Cap Spartel, Tanca sahili ve canlı Grand/Petit Socco meydanları. Konaklama Tanca'da."},{"day":"5. Gün","date":"8 Temmuz - Şefşaven & Fes","title":"Tanca - Şefşaven - Fes","activities":["Şefşaven'e transfer (~1,5 saat)","Mavi sokaklar & Medina","Uta el Hammam Meydanı","Ras El Ma","Fes'e transfer (~3 saat)"],"description":"Kahvaltı sonrası Rif Dağları eteğindeki, mavi boyalı sokakları ve huzurlu atmosferiyle ünlü Şefşaven'e (~1,5 saat) gidiyoruz. Medina, Kasbah Meydanı, Uta el Hammam Meydanı ve Ras El Ma su kaynağı; fotoğraf ve serbest zaman. Akşam ~3 saatlik yolculukla Fes'e. Konaklama Fes'te."},{"day":"6. Gün","date":"9 Temmuz - Fes","title":"Fes Şehir Turu (UNESCO Fes el-Bali)","activities":["Bab Bou Jeloud","Karaouiyine Üniversitesi & Camii","Attarine Medresesi","Mevlay İdris Türbesi","Deri tabakhaneleri","Kraliyet Sarayı kapıları"],"description":"Tam gün Fes şehir turu. Şehrin simgesel kapısı Bab Bou Jeloud'dan UNESCO korumasındaki Fes el-Bali Medinası'na giriyoruz. Dünyanın en eski üniversitelerinden ve İslam ilim tarihinde çok önemli bir yere sahip Karaouiyine Üniversitesi ve Camii, Attarine Medresesi, şehir için manevi öneme sahip Mevlay İdris Türbesi, asırlardır geleneksel yöntemlerle çalışan deri tabakhaneleri ve Kraliyet Sarayı kapıları. Konaklama Fes'te."},{"day":"7. Gün","date":"10 Temmuz - Dönüş","title":"Fes - Kazablanka - İstanbul","activities":["Otel kahvaltısı","Kazablanka Havalimanı'na transfer","Dönüş uçuşu (18:00)"],"description":"Kahvaltı sonrası Kazablanka Havalimanı'na hareket ediyoruz (15:00 varış). 18:00 uçağımızla dönüş; 11 Temmuz 01:40'ta İstanbul'a iniş."}]$itin$::jsonb, $faq$[{"question":"İptal ve iade koşulları nelerdir?","answer":"Tur tarihine 30 günden daha uzun süre varken yapılan iptallerde ödemenizin tamamı iade edilir. Tura 21-30 gün kala yapılan iptallerde tutarın %50'si tahsil edilir. 21 günden az süre kala yapılan iptallerde ücretin tamamı tahsil edilir."},{"question":"Rezervasyon ve ödeme nasıl yapılır?","answer":"375 EUR kapora ile kesin kayıt oluşur; kalan bakiye tur tarihinden önce taksitlerle tamamlanır (7 Nisan itibarıyla yarısı ödenmiş olmalıdır). Çocuk (2-6 yaş) 1.050 EUR, bebek (0-2 yaş) 400 EUR."},{"question":"Uçuş bilgileri nelerdir?","answer":"Gidiş: 4 Temmuz 01:30 Sabiha Gökçen → Kazablanka (Air Arabia 30438). Dönüş: 10 Temmuz 18:00 Kazablanka → Sabiha Gökçen, 11 Temmuz 01:40 varış (30437). 20 kg bagaj ve ikram dahil."},{"question":"Konaklama nerede?","answer":"Tur boyunca 3-4 yıldızlı otellerde 6 gece, kahvaltı dahil (Marakeş, Kazablanka, Tanca, Fes)."},{"question":"Kimler katılabilir?","answer":"Turlarımız aile ve hanımların katılımına uygundur; grubun uyumu ve misafirlerimizin konforu için bireysel erkek misafir kabul edemiyor, beylerin anlayışına sığınıyoruz. Erkek misafirlerimiz aile veya grup katılımıyla aramıza katılabilir. Maksimum 15 kişilik butik gruplar."},{"question":"Pasaport için bir şart var mı?","answer":"Pasaportunuzun, gezi bitiş tarihi itibarıyla en az 6 ay geçerli olması gerekmektedir."}]$faq$::jsonb, true, true, 2, now(), now())
ON CONFLICT (slug) DO UPDATE SET title=EXCLUDED.title, description=EXCLUDED.description, "pricePerPerson"=EXCLUDED."pricePerPerson", currency=EXCLUDED.currency, "priceNote"=EXCLUDED."priceNote", "groupSize"=EXCLUDED."groupSize", type=EXCLUDED.type, destination=EXCLUDED.destination, image=EXCLUDED.image, dates=EXCLUDED.dates, duration=EXCLUDED.duration, "startDate"=EXCLUDED."startDate", "endDate"=EXCLUDED."endDate", highlights=EXCLUDED.highlights, included=EXCLUDED.included, "notIncluded"=EXCLUDED."notIncluded", itinerary=EXCLUDED.itinerary, faq=EXCLUDED.faq, featured=EXCLUDED.featured, "order"=EXCLUDED."order", "updatedAt"=now();
INSERT INTO "Tour" (id, slug, title, description, "pricePerPerson", currency, "priceNote", "groupSize", type, destination, image, gallery, "specialOffer", dates, duration, "startDate", "endDate", highlights, included, "notIncluded", itinerary, faq, featured, active, "order", "createdAt", "updatedAt") VALUES (gen_random_uuid()::text, 'misir-turu-nisan-2026', $q$Mısır Turu - Kahire & Şarm el Şeyh (Nisan)$q$, $q$Giza Piramitleri, tarihi Kahire, Şarm el Şeyh'te 5 yıldızlı her şey dahil resort, ATV safari ve Ras Muhammed dalış turuyla 5 günlük Mısır deneyimi. Namaz vakitlerine uygun.$q$, 899, 'EUR', $q$Çocuk (3-9 yaş): 699 EUR · Bebek (0-3 yaş): 549 EUR · Tek kişilik oda farkı: +150 EUR · 200 EUR kapora ile rezervasyon.$q$, $q$Maksimum 15 kişi (butik)$q$, 'international', $q$Mısır (Kahire & Şarm el Şeyh)$q$, $q$/uploads/media/egypt.jpg$q$, ARRAY[]::text[], false, $q$23 - 28 Nisan 2026$q$, $q$5 gün / 4 gece$q$, '2026-04-23', '2026-04-28', ARRAY[$q$Giza Piramitleri ve Mısır Medeniyeti Müzesi$q$,$q$Tarihi Kahire: El-Ezher, Hz. Hüseyin Camii, Han El Halili$q$,$q$Şarm el Şeyh'te 5 yıldızlı her şey dahil resort$q$,$q$ATV çöl safarisi ve bedevi gecesi$q$,$q$Ras Muhammed & Beyaz Ada tekne turu, şnorkel ve dalış$q$,$q$Nil'de gün batımı felucca turu$q$,$q$AJET ile gidiş-dönüş uçak bileti (+20 kg bagaj)$q$,$q$Namaz vakitlerine uygun program · Her şey dahil · Kapıda vize dahil$q$]::text[], ARRAY[$q$Sabiha Gökçen - Kahire & Şarm el Şeyh - Sabiha Gökçen AJET gidiş-dönüş uçak bileti (+20 kg bagaj)$q$,$q$Kahire'de 2 gece kahvaltı dahil konaklama$q$,$q$Şarm el Şeyh'te 2 gece 5 yıldızlı her şey dahil resort (Sharm Resort & Plaza)$q$,$q$Tüm şehir içi ve şehirlerarası transferler$q$,$q$Tüm kahvaltı ve akşam yemekleri$q$,$q$Tüm müze ve ören yeri giriş ücretleri$q$,$q$ATV çöl safarisi ve bedevi gecesi$q$,$q$Nil felucca tekne turu$q$,$q$Ras Muhammed tekne turu ve tüplü dalış$q$,$q$Seyahat sağlık sigortası$q$,$q$Kapıda vize$q$]::text[], ARRAY[$q$Yurt dışı çıkış harcı (havalimanında 1250 TL)$q$,$q$Tüm şahsi harcamalar$q$,$q$Yerel bahşişler (ortalama 10 dolar)$q$,$q$Piramit iç giriş ücreti$q$]::text[], $itin$[{"day":"1. Gün","date":"23 Nisan - Tarihi Kahire","title":"İstanbul - Kahire · Tarihi Kahire Turu","activities":["Sabiha Gökçen kalkış (11:40)","Kahire'ye varış (14:25)","İmam Şâfiî Kabri","El-Ezher Camii","Hz. Hüseyin Camii","El-Muiz Caddesi","El Fishawy Cafe","Han El Halili Çarşısı"],"description":"Sabiha Gökçen'den 13:00 kalkış, 14:25'te Kahire'ye varış. Vize ve bagaj sonrası tarihi Kahire turu: İmam Şâfiî Kabri, El-Ezher Camii ve Külliyesi, Hz. Hüseyin Camii; Fatımi ve Memluk yapılarıyla açık hava müzesi El-Muiz Caddesi; Mehmet Akif Ersoy'un da uğradığı El Fishawy Cafe'de mola ve Han El Halili Çarşısı'nda serbest alışveriş. Akşam yemeği. Konaklama Kahire'de."},{"day":"2. Gün","date":"24 Nisan - Antik Mısır & Giza","title":"Giza Piramitleri · Mısır Müzesi · Nil Felucca","activities":["Giza Piramitleri (alan girişi dahil)","Papirüs Atölyesi","Mısır Medeniyeti Müzesi","Selahaddin Kalesi & Muhammed Ali Camii","Nil'de felucca turu"],"description":"Kahvaltı sonrası Giza Piramitleri (alan girişi dahil; piramit içi hariç), papirüs atölyesi ve Mısır Medeniyeti Müzesi. Öğleden sonra Kahire'yi gören Selahaddin Kalesi ve Osmanlı mimarili Kavalalı Mehmet Ali Paşa Camii. Akşam Nil Nehri'nde gün batımında felucca turu, akşam yemeği. Konaklama Kahire'de."},{"day":"3. Gün","date":"25 Nisan - Şarm el Şeyh","title":"Kahire - Şarm el Şeyh · ATV Safari & Bedevi Gecesi","activities":["Şarm el Şeyh'e transfer","Her şey dahil otele yerleşme","ATV çöl safarisi","Bedevi gecesi (yemek & gösteri)"],"description":"Sabah erken Şarm el Şeyh'e hareket; Kızıldeniz'in tatil cennetine varışta her şey dahil otele yerleşme ve dinlenme. Öğleden sonra ATV çöl safarisi; akşam geleneksel müzik, yerel lezzetler ve otantik atmosferle bedevi gecesi. Konaklama Şarm el Şeyh'te."},{"day":"4. Gün","date":"26 Nisan - Kızıldeniz","title":"Ras Muhammed & Beyaz Ada Tekne Turu","activities":["Öğle yemekli tekne turu","Ras Muhammed & Beyaz Ada","Mercan resiflerinde şnorkel","Tüplü dalış (opsiyonel)"],"description":"Kahvaltı sonrası dünyanın önde gelen dalış ve doğa noktalarından Ras Muhammed ve Beyaz Ada'ya öğle yemekli tekne turu. Turkuaz sularda yüzme molaları, mercan resiflerinde şnorkel ve dileyen için tüplü dalış. Öğle yemeği teknede. Akşam otele dönüş. Konaklama Şarm el Şeyh'te."},{"day":"5. Gün","date":"27-28 Nisan - Şehir Turu & Dönüş","title":"Şarm el Şeyh Şehir Turu ve Dönüş","activities":["Otel çıkışı","El Sahaba Camii","Old Bazaar","Naama Bay","Havalimanına transfer","Dönüş uçuşu (28 Nisan 04:00)"],"description":"Kahvaltı ve check-out sonrası şehir turu: zarif mimarisiyle El Mustafa ve görkemli El Sahaba Camii, Old Bazaar'da serbest zaman, Kızıldeniz manzaralı Farsha Cafe ve Naama Bay sahil yürüyüşü. Ardından havalimanına transfer; 28 Nisan 04:00 uçağımızla dönüş (06:40 varış)."}]$itin$::jsonb, $faq$[{"question":"İptal ve iade koşulları nelerdir?","answer":"Tur tarihine 30 günden daha uzun süre varken yapılan iptallerde ödemenizin tamamı iade edilir. Tura 21-30 gün kala yapılan iptallerde tutarın %50'si tahsil edilir. 21 günden az süre kala yapılan iptallerde ücretin tamamı tahsil edilir."},{"question":"Rezervasyon ve ödeme nasıl yapılır?","answer":"200 EUR kapora ile kesin kayıt oluşur; kalan bakiye tur tarihinden önce tamamlanır (1 Nisan itibarıyla en az yarısı ödenmiş olmalıdır). Çocuk (3-9 yaş) 699 EUR, bebek (0-3 yaş) 549 EUR, tek kişilik oda farkı +150 EUR."},{"question":"Uçuş bilgileri nelerdir?","answer":"Gidiş: 23 Nisan 13:00 Sabiha Gökçen → Kahire (AJET VF391). Dönüş: 28 Nisan 04:00 Şarm el Şeyh → Sabiha Gökçen, 06:40 varış (AJET VF256). 20 kg bagaj dahil."},{"question":"Vize gerekiyor mu, ek resmi ücretler var mı?","answer":"Kapıda vize fiyata dahildir. Yurt dışı çıkış harcı (havalimanında ödenebilir, 1250 TL) ve tüm şahsi harcamalar misafire aittir."},{"question":"Konaklama nerede?","answer":"Kahire'de 2 gece kahvaltı dahil; Şarm el Şeyh'te 2 gece 5 yıldızlı her şey dahil Sharm Resort & Plaza Hotel."},{"question":"Kimler katılabilir?","answer":"Turlarımız aile ve hanımların katılımına uygundur; grubun uyumu ve misafirlerimizin konforu için bireysel erkek misafir kabul edemiyor, beylerin anlayışına sığınıyoruz. Erkek misafirlerimiz aile veya grup katılımıyla aramıza katılabilir. Maksimum 15 kişilik butik gruplar."},{"question":"Pasaport için bir şart var mı?","answer":"Pasaportunuzun, gezi bitiş tarihi itibarıyla en az 6 ay geçerli olması gerekmektedir."}]$faq$::jsonb, false, true, 20, now(), now())
ON CONFLICT (slug) DO UPDATE SET title=EXCLUDED.title, description=EXCLUDED.description, "pricePerPerson"=EXCLUDED."pricePerPerson", currency=EXCLUDED.currency, "priceNote"=EXCLUDED."priceNote", "groupSize"=EXCLUDED."groupSize", type=EXCLUDED.type, destination=EXCLUDED.destination, image=EXCLUDED.image, dates=EXCLUDED.dates, duration=EXCLUDED.duration, "startDate"=EXCLUDED."startDate", "endDate"=EXCLUDED."endDate", highlights=EXCLUDED.highlights, included=EXCLUDED.included, "notIncluded"=EXCLUDED."notIncluded", itinerary=EXCLUDED.itinerary, faq=EXCLUDED.faq, featured=EXCLUDED.featured, "order"=EXCLUDED."order", "updatedAt"=now();
INSERT INTO "Tour" (id, slug, title, description, "pricePerPerson", currency, "priceNote", "groupSize", type, destination, image, gallery, "specialOffer", dates, duration, "startDate", "endDate", highlights, included, "notIncluded", itinerary, faq, featured, active, "order", "createdAt", "updatedAt") VALUES (gen_random_uuid()::text, 'ozbekistan-turu', $q$Özbekistan Turu - Hiva, Buhara, Semerkant, Taşkent$q$, $q$İçan Kala'dan Registan Meydanı'na; İmam Buhari ve Bahauddin Nakşibendi türbelerinden Şah-ı Zinde'ye, İslam medeniyetinin kalbinde 6 günlük butik İpek Yolu turu. Türkçe rehberlik, namaz vakitlerine uygun.$q$, 1250, 'EUR', $q$Çocuk (3-9 yaş): 900 EUR · Bebek (0-3 yaş): 700 EUR · 270 EUR kapora ile rezervasyon · Kampanya fiyatı.$q$, $q$Maksimum 15 kişi (butik)$q$, 'international', $q$Özbekistan (Hiva · Buhara · Semerkant · Taşkent)$q$, $q$/uploads/media/samarkand.jpg$q$, ARRAY[]::text[], false, $q$24 - 30 Mayıs 2026$q$, $q$6 gün / 5 gece$q$, '2026-05-24', '2026-05-30', ARRAY[$q$Hiva İçan Kala açık hava müzesi (UNESCO)$q$,$q$Buhara: Ark Kalesi, Kalon Minaresi, Mir Arab Medresesi$q$,$q$Semerkant: Registan Meydanı, Gur-i Emir, Şah-ı Zinde$q$,$q$İmam Buhari ve Bahauddin Nakşibendi türbeleri$q$,$q$Taşkent: Hazreti İmam Kompleksi (Hz. Osman Mushaf-ı Şerifi)$q$,$q$THY ile gidiş-dönüş uçak bileti (+20 kg bagaj)$q$,$q$Türkçe rehberlik · 5 gece kahvaltı dahil konaklama$q$,$q$Namaz vakitlerine uygun program$q$]::text[], ARRAY[$q$Gidiş-dönüş uçak biletleri (+20 kg bagaj)$q$,$q$3-4 yıldızlı otellerde 5 gece konaklama (kahvaltı dahil)$q$,$q$Şehir içi ve şehirlerarası tüm transferler$q$,$q$Tüm kahvaltı ve akşam yemekleri$q$,$q$Türkçe rehberlik hizmeti$q$,$q$Programdaki tüm ziyaret ve geziler için giriş biletleri$q$,$q$Seyahat sağlık sigortası$q$]::text[], ARRAY[$q$Yurt dışı çıkış harcı (havalimanında 1250 TL)$q$,$q$Tüm şahsi harcamalar$q$,$q$Yerel bahşişler (ortalama 10 dolar)$q$]::text[], $itin$[{"day":"1. Gün","date":"24 Mayıs - Hiva","title":"İstanbul - Ürgenç - Hiva (İçan Kala)","activities":["İstanbul Havalimanı buluşma (23 Mayıs 22:00)","Ürgenç'e varış","İçan Kala & Ata Darvaza","Köhne Ark Sarayı","Muhammed Emin Han Medresesi & Kelte Minar","Cuma Camii","Pahlavan Mahmud Türbesi"],"description":"23 Mayıs 22:00'de İstanbul Havalimanı'nda buluşuyor, 01:05 uçağımızla Ürgenç'e gidiyoruz. Rehberimiz eşliğinde, Orta Çağ dokusunu en iyi koruyan UNESCO şehri Hiva'ya geçiyoruz. Surlar içindeki açık hava müzesi İçan Kala'yı Ata Darvaza kapısından gezmeye başlıyoruz: Köhne Ark Sarayı, şehrin simgesi Muhammed Emin Han Medresesi ve Kelte Minar, Muhammed Rahim Han Medresesi, Taş Avlu Sarayı, ahşap sütunlu Cuma Camii, İslam Hoca Medresesi ve Pahlavan Mahmud Türbesi. Akşam yemeği. Konaklama Hiva'da."},{"day":"2. Gün","date":"25 Mayıs - Buhara","title":"Hiva - Buhara · Labi Havuz","activities":["Buhara'ya yolculuk (~7 saat)","Çöl manzaraları","Otele yerleşme","Labi Havuz Meydanı (serbest)"],"description":"Kahvaltı sonrası Orta Asya'nın kadim ilim, kültür ve ticaret merkezi Buhara'ya yaklaşık 7 saatlik yolculuk; yol boyunca uçsuz bucaksız çöl manzaraları. Otele yerleşme ve dinlenmenin ardından akşam yemeği; tarih boyunca tüccar ve ilim insanlarının buluşma noktası Labi Havuz Meydanı'nda serbest zaman. Konaklama Buhara'da."},{"day":"3. Gün","date":"26 Mayıs - Buhara","title":"Buhara Şehir Turu · Nakşibendi Türbesi","activities":["Bahauddin Nakşibendi Türbesi","İsmail Samani Türbesi","Eyüp Peygamber Çeşmesi","Ark Kalesi","Kalon Mescidi & Minaresi","Mir Arab Medresesi","Uluğ Bey & Abdülaziz Han Medreseleri"],"description":"Kahvaltı sonrası Nakşibendi tarikatının kurucusu Bahauddin Nakşibendi Türbesi, İsmail Samani Türbesi ve Eyüp Peygamber Çeşmesi. Eski Şehir'de Ark Kalesi, Kalon Mescidi ve Minaresi, hâlâ eğitim veren Mir Arab Medresesi, Bolo Houz Camii, Uluğ Bey ve Abdülaziz Han Medreseleri; İpek Yolu'nun kalbinde serbest alışveriş. Akşam yemeği. Konaklama Buhara'da."},{"day":"4. Gün","date":"27 Mayıs - Semerkant","title":"Buhara - Semerkant · İmam Buhari Türbesi","activities":["Semerkant'a yolculuk (~5 saat)","Hoca Abdülhalik Gijduvani Türbesi","Seramik atölyesi","İmam Buhari Türbesi","İmam Maturidi Türbesi"],"description":"Kahvaltı sonrası Semerkant'a ~5 saatlik yolculuk. Yol üzerinde Nakşibendi silsilesinin öncülerinden Hoca Abdülhalik Gijduvani Türbesi ve geleneksel seramik atölyesi. Semerkant'a varırken hadis ilminin en büyük isimlerinden İmam Buhari ile Mahdumi A'zam türbeleri; ardından İmam Maturidi ve Hace Ubeydullah-ı Ahrar ziyaretleri. Akşam yemeği. Konaklama Semerkant'ta."},{"day":"5. Gün","date":"28 Mayıs - Semerkant","title":"Semerkant Şehir Turu · Registan & Şah-ı Zinde","activities":["Gur-i Emir (Emir Timur Türbesi)","Uluğ Bey Rasathanesi","Şah-ı Zinde Türbeler Kompleksi","Hazret Hızır Camii","Bibi Hanım Camii","Siyob Pazarı","Registan Meydanı"],"description":"Kahvaltı sonrası Emir Timur'un türbesi Gur-i Emir ile başlıyoruz; Uluğ Bey Rasathanesi, asırlardır ziyaret edilen Şah-ı Zinde Türbeler Kompleksi (Kusam bin Abbas ve birçok İslam büyüğünün medfun olduğu), Hazret Hızır Camii, görkemli Bibi Hanım Camii ve Siyob Pazarı. Üç büyük medreseyle çevrili, Orta Asya İslam mimarisinin zirvesi Registan Meydanı (Uluğ Bey, Tilla Kari, Şirdar). Akşam yemeği. Konaklama Semerkant'ta."},{"day":"6. Gün","date":"29-30 Mayıs - Taşkent & Dönüş","title":"Semerkant - Taşkent - İstanbul","activities":["Taşkent'e yolculuk (~5 saat)","Hazreti İmam Kompleksi (Mushaf-ı Şerif)","Emir Timur & Bağımsızlık Meydanı","Kökeldaş Medresesi","Çorsu Pazarı","Veda yemeği & dönüş"],"description":"Kahvaltı sonrası başkent Taşkent'e ~5 saatlik yolculuk. Hz. Osman dönemine ait Mushaf-ı Şerif'e ev sahipliği yapan Hazreti İmam Kompleksi, Emir Timur Meydanı, Bağımsızlık Meydanı, hâlâ eğitim veren Kökeldaş Medresesi ve Çorsu Pazarı'nda serbest zaman. Veda yemeğinin ardından havalimanına transfer; 30 Mayıs ilk saatlerinde İstanbul'a dönüş."}]$itin$::jsonb, $faq$[{"question":"İptal ve iade koşulları nelerdir?","answer":"Tur tarihine 30 günden daha uzun süre varken yapılan iptallerde ödemenizin tamamı iade edilir. Tura 21-30 gün kala yapılan iptallerde tutarın %50'si tahsil edilir. 21 günden az süre kala yapılan iptallerde ücretin tamamı tahsil edilir."},{"question":"Rezervasyon ve ödeme nasıl yapılır?","answer":"270 EUR (%20) kapora ile kesin kayıt oluşur; kalan tutar 9 Mayıs'a kadar taksitlendirilebilir (2 Mayıs itibarıyla yarısı ödenmiş olmalıdır). Çocuk (3-9 yaş) 900 EUR, bebek (0-3 yaş) 700 EUR."},{"question":"Uçuş bilgileri nelerdir?","answer":"Gidiş: 24 Mayıs 01:05 İstanbul → Ürgenç (THY TK262). Dönüş: 30 Mayıs 02:20 Taşkent → İstanbul, 05:35 varış (THY TK371). 20 kg bagaj dahil."},{"question":"Konaklama nerede?","answer":"3-4 yıldızlı otellerde 5 gece, kahvaltı dahil (Hiva, Buhara, Semerkant)."},{"question":"Kimler katılabilir?","answer":"Turlarımız aile ve hanımların katılımına uygundur; grubun uyumu ve misafirlerimizin konforu için bireysel erkek misafir kabul edemiyor, beylerin anlayışına sığınıyoruz. Erkek misafirlerimiz aile veya grup katılımıyla aramıza katılabilir. Maksimum 15 kişilik butik gruplar."},{"question":"Pasaport için bir şart var mı?","answer":"Pasaportunuzun, gezi bitiş tarihi itibarıyla en az 6 ay geçerli olması gerekmektedir."}]$faq$::jsonb, false, true, 21, now(), now())
ON CONFLICT (slug) DO UPDATE SET title=EXCLUDED.title, description=EXCLUDED.description, "pricePerPerson"=EXCLUDED."pricePerPerson", currency=EXCLUDED.currency, "priceNote"=EXCLUDED."priceNote", "groupSize"=EXCLUDED."groupSize", type=EXCLUDED.type, destination=EXCLUDED.destination, image=EXCLUDED.image, dates=EXCLUDED.dates, duration=EXCLUDED.duration, "startDate"=EXCLUDED."startDate", "endDate"=EXCLUDED."endDate", highlights=EXCLUDED.highlights, included=EXCLUDED.included, "notIncluded"=EXCLUDED."notIncluded", itinerary=EXCLUDED.itinerary, faq=EXCLUDED.faq, featured=EXCLUDED.featured, "order"=EXCLUDED."order", "updatedAt"=now();
DELETE FROM "Tour" WHERE slug IN ('dubai-abu-dabi-turu','fas-binbir-gece-turu');
COMMIT;
SELECT slug, "startDate"::date, "endDate"::date, "pricePerPerson", featured, active FROM "Tour" ORDER BY "order";
